class InMemorySecureVault(
    private val securityEngine: SecurityEngine
) : SecureStorage {
    private val tokenStore = ConcurrentHashMap<String, Pair<ProtectedPayload, Long>>()

    override fun protect(plain: ByteArray): Result<ProtectedPayload> {
        return securityEngine.encrypt(plain)
    }

    override fun reveal(payload: ProtectedPayload): Result<ByteArray> {
        return securityEngine.decrypt(payload)
    }

    override fun sign(data: ByteArray): Result<String> {
        return securityEngine.hmac(data)
    }

    override fun tokenizedStore(value: String): Result<TokenizedValue> {
        val token = UUID.randomUUID().toString().replace("-", "")
        val protected = securityEngine.encrypt(value.toByteArray(Charsets.UTF_8)).getOrElse {
            return Result.failure(it)
        }
        val expiresAt = System.currentTimeMillis() + PaymentModuleConfig.TOKEN_TTL_MS
        tokenStore[token] = protected to expiresAt
        return Result.success(TokenizedValue(token, expiresAt))
    }

    override fun resolveToken(token: String): Result<String> {
        purgeExpired()
        val found = tokenStore[token] ?: return Result.failure(IllegalArgumentException("Unknown token"))
        if (System.currentTimeMillis() > found.second) {
            tokenStore.remove(token)
            return Result.failure(IllegalStateException("Expired token"))
        }
        return securityEngine.decrypt(found.first).map {
            it.toString(Charsets.UTF_8)
        }
    }

    override fun purgeExpired() {
        val now = System.currentTimeMillis()
        tokenStore.entries.removeIf { it.value.second < now }
    }
}

