interface PaymentProcessor {
    fun process(request: PaymentRequest): PaymentResult
}

class PaymentRequestValidator {
    fun validate(request: PaymentRequest): PaymentError? {
        if (request.paymentMethodToken.isBlank()) return PaymentError.InvalidRequest
        if (request.customer.customerId.isBlank()) return PaymentError.InvalidRequest
        if (request.customer.deviceIdHash.isBlank()) return PaymentError.InvalidRequest
        if (request.money.amount <= BigDecimal.ZERO) return PaymentError.InvalidAmount
        try {
            Currency.getInstance(request.money.currencyCode.uppercase(Locale.US))
        } catch (_: IllegalArgumentException) {
            return PaymentError.InvalidCurrency
        }

        when (request.type) {
            PaymentType.IN_APP_PURCHASE -> {
                val iap = request.iapDetails ?: return PaymentError.InvalidRequest
                if (iap.productId.isBlank() || iap.orderId.isBlank()) return PaymentError.InvalidRequest
            }
            PaymentType.WALLET_TRANSFER -> {
                val wallet = request.walletDetails ?: return PaymentError.InvalidRequest
                if (wallet.walletId.isBlank()) return PaymentError.InvalidRequest
            }
        }

        return null
    }
}

class DefaultPaymentProcessor(
    private val secureStorage: SecureStorage
) : PaymentProcessor {

    override fun process(request: PaymentRequest): PaymentResult {
        val normalizedMoney = request.money.normalized()
        val tokenRaw = secureStorage.resolveToken(request.paymentMethodToken).getOrElse {
            return PaymentResult.Failure(PaymentError.AuthenticationFailed)
        }

        val dataToSign = buildString {
            append(request.requestId)
            append("|")
            append(request.type.name)
            append("|")
            append(normalizedMoney.amount.toPlainString())
            append("|")
            append(normalizedMoney.currencyCode)
            append("|")
            append(request.customer.customerId)
            append("|")
            append(hashSha256(tokenRaw))
        }.toByteArray(Charsets.UTF_8)

        val signature = secureStorage.sign(dataToSign).getOrElse {
            return PaymentResult.Failure(PaymentError.EncryptionFailed)
        }

        val receipt = PaymentReceipt(
            transactionId = UUID.randomUUID().toString(),
            requestId = request.requestId,
            type = request.type,
            status = TransactionStatus.CAPTURED,
            amount = normalizedMoney,
            processedAt = Date().time,
            authCode = UUID.randomUUID().toString().take(8).uppercase(Locale.US),
            receiptSignature = signature
        )

        return PaymentResult.Success(receipt)
    }

    private fun hashSha256(value: String): String {
        return MessageDigest.getInstance("SHA-256")
            .digest(value.toByteArray(Charsets.UTF_8))
            .toHex()
    }
}

class PaymentService(
    private val context: Context,
    private val deviceSecurityPolicy: DeviceSecurityPolicy = DefaultDeviceSecurityPolicy(context),
    private val validator: PaymentRequestValidator = PaymentRequestValidator(),
    private val securityEngine: SecurityEngine = SecurityEngine(context, deviceSecurityPolicy),
    private val secureStorage: SecureStorage = InMemorySecureVault(securityEngine),
    private val processor: PaymentProcessor = DefaultPaymentProcessor(secureStorage)
) {
    fun tokenizePaymentMethod(rawPaymentSecret: String): Result<TokenizedValue> {
        if (!deviceSecurityPolicy.isDeviceSupported()) {
            return Result.failure(IllegalStateException(PaymentError.UnsupportedDevice.message))
        }
        if (rawPaymentSecret.isBlank()) {
            return Result.failure(IllegalArgumentException(PaymentError.InvalidRequest.message))
        }
        return secureStorage.tokenizedStore(rawPaymentSecret)
    }

    fun processPayment(request: PaymentRequest): PaymentResult {
        if (!deviceSecurityPolicy.isDeviceSupported()) {
            return PaymentResult.Failure(PaymentError.UnsupportedDevice)
        }
        val validationError = validator.validate(request)
        if (validationError != null) {
            return PaymentResult.Failure(validationError)
        }
        secureStorage.purgeExpired()
        return processor.process(request)
    }

    fun clearExpiredSensitiveState() {
        secureStorage.purgeExpired()
    }

    fun createCustomerRef(customerId: String, deviceIdentifier: String): CustomerRef {
        return CustomerRef(
            customerId = customerId.trim(),
            deviceIdHash = sha256(deviceIdentifier.trim())
        )
    }

    private fun sha256(value: String): String {
        return MessageDigest.getInstance("SHA-256")
            .digest(value.toByteArray(Charsets.UTF_8))
            .toHex()
    }
}

